fn first<T>(list: &[T]) -> &T {
    &list[0]
}

fn main() {
    let nums = vec![1, 2, 3];
    let strs = vec!["a", "b", "c"];
    println!("{}", first(&nums));
    println!("{}", first(&strs));
}

fn largest<T: PartialOrd>(list: &[T]) -> &T {
    let mut largest = &list[0];
    for item in list {
        if item > largest { largest = item; }
    }
    largest
}

fn main() {
    println!("{}", largest(&[34, 50, 25, 100, 65]));
    println!("{}", largest(&[1.5, 2.7, 0.3]));
}

#[derive(Debug)]
struct Pair<T> {
    first: T,
    second: T,
}

impl<T: std::fmt::Display + PartialOrd> Pair<T> {
    fn larger(&self) -> &T {
        if self.first > self.second { &self.first } else { &self.second }
    }
}

fn main() {
    let p = Pair { first: 5, second: 3 };
    println!("{:?} larger: {}", p, p.larger());
}

#[derive(Debug)]
struct KeyValue<K, V> {
    key: K,
    value: V,
}

fn main() {
    let entry = KeyValue { key: "age", value: 30 };
    let entry2 = KeyValue { key: 1, value: 3.14 };
    println!("{:?}", entry);
    println!("{:?}", entry2);
}

#[derive(Debug)]
enum Maybe<T> {
    Just(T),
    Nothing,
}

fn safe_head<T: Clone>(v: &[T]) -> Maybe<T> {
    if v.is_empty() { Maybe::Nothing } else { Maybe::Just(v[0].clone()) }
}

fn main() {
    println!("{:?}", safe_head(&[1, 2, 3]));
    println!("{:?}", safe_head::<i32>(&[]));
}

fn add<T: std::ops::Add<Output = T>>(a: T, b: T) -> T {
    a + b
}

fn main() {
    println!("{}", add(1_i32, 2));
    println!("{}", add(1.5_f64, 2.5));
    println!("{}", add(10_u64, 20));
}

fn print_all(items: impl Iterator<Item = i32>) {
    for item in items {
        print!("{} ", item);
    }
    println!();
}

fn main() {
    print_all(vec![1, 2, 3].into_iter());
    print_all(1..=5);
}

use std::marker::PhantomData;

struct Id<T> {
    value: u64,
    _marker: PhantomData<T>,
}

struct User;
struct Post;

fn main() {
    let user_id: Id<User> = Id { value: 1, _marker: PhantomData };
    let post_id: Id<Post> = Id { value: 1, _marker: PhantomData };
    println!("user id: {}", user_id.value);
    println!("post id: {}", post_id.value);
    // Cannot mix them: user_id and post_id are different types
}
